   157→
   158→    /// Helper: compute backfill candidates using the same logic as main()
   159→    fn backfill_candidates(last: Option<u32>, latest: u32, limit: u32) -> Vec<u32> {
   160→        let start = last.map(|n| n.saturating_add(1)).unwrap_or_else(|| {
   161→            if limit > 0 {
   162→                latest.saturating_sub(limit - 1)
   163→            } else {
   164→                latest
   165→            }
   166→        });
   167→        if limit > 0 {
   168→            (start..=latest).take(limit as usize).collect()
   169→        } else {
   170→            vec![latest]
   171→        }
   172→    }
   173→
   174→    // ── backfill candidate logic ──────────────────────────────────────────────
   175→
   176→    #[test]
   177→    fn backfill_candidates_empty_db() {
   178→        // No prior history + backfill enabled → deliver limit comics ending at latest
   179→        assert_eq!(backfill_candidates(None, 100, 5), vec![96, 97, 98, 99, 100]);
   180→    }
   181→
   182→    #[test]
   183→    fn backfill_candidates_empty_db_limit_one() {
   184→        // limit=1 must not underflow (100 - (1-1) = 100)
   185→        assert_eq!(backfill_candidates(None, 100, 1), vec![100]);
   186→    }
   187→
   188→    #[test]
   189→    fn backfill_candidates_up_to_date() {
   190→        // Already seen the latest — empty list
   191→        assert_eq!(backfill_candidates(Some(100), 100, 5), Vec::<u32>::new());
   192→    }
   193→
   194→    #[test]
   195→    fn backfill_candidates_with_gap() {
   196→        assert_eq!(backfill_candidates(Some(98), 101, 5), vec![99, 100, 101]);
   197→    }
   198→
   199→    #[test]
   200→    fn backfill_candidates_capped() {
   201→        // Gap of 11 but limit=3 → only first 3
   202→        assert_eq!(backfill_candidates(Some(90), 101, 3), vec![91, 92, 93]);
   203→    }
   204→
   205→    #[test]
   206→    fn backfill_candidates_limit_zero() {
   207→        // limit=0 disables backfill — only latest
   208→        assert_eq!(backfill_candidates(Some(98), 101, 0), vec![101]);
   209→    }
   210→
   211→    // ── backfill 404 marked seen ──────────────────────────────────────────────
   212→
   213→    #[test]
   214→    fn backfill_404_marked_seen() {
   215→        // When fetch_comic_by_num returns Ok(None), the num should be recorded as seen
   216→        // so the next run advances past it. We test this via the DB directly.
   217→        let (_dir, db) = db::make_db();
   218→        let placeholder = make_comic(404);
   219→        record_first_seen(&db, &placeholder).unwrap();
   220→        assert!(is_seen(&db, &placeholder).unwrap());
   221→        // email_sent should be false — a 404 placeholder was never emailed
   222→        let rtx = db.begin_read().unwrap();
   223→        let table = rtx.open_table(COMICS_TABLE).unwrap();
   224→        let json = table.get(404u32).unwrap().unwrap().value().to_owned();
   225→        let rec: ComicRecord = serde_json::from_str(&json).unwrap();
   226→        assert!(!rec.email_sent);
   227→    }
   228→}
