     3→#[derive(Debug)]
     4→pub struct Config {
     5→    pub mail_to: Vec<String>,
     6→    pub mail_from: String,
     7→    pub download: bool,
     8→    pub mail_attachment: bool,
     9→    pub smtp_server: String,
    10→    pub smtp_port: u16,
    11→    pub smtp_starttls: bool,
    12→    pub smtp_username: Option<String>,
    13→    pub smtp_password: Option<String>,
    14→    pub backfill_limit: u32,
    15→}
    16→
    17→pub fn load_config() -> anyhow::Result<Config> {
    18→    fn env(key: &str) -> anyhow::Result<String> {
    19→        std::env::var(key).with_context(|| format!("missing env var {key}"))
    20→    }
    21→
    22→    fn env_bool(key: &str, default: bool) -> bool {
    23→        match std::env::var(key) {
    24→            Ok(v) => matches!(v.trim().to_ascii_lowercase().as_str(), "true" | "1" | "yes"),
    25→            Err(_) => default,
    26→        }
    27→    }
    28→
    29→    let config = Config {
    30→        mail_to: env("XKCD_MAIL_TO")?
    31→            .split(',')
    32→            .map(|s| s.trim().to_string())
    33→            .filter(|s| !s.is_empty())
    34→            .collect(),
    35→        mail_from: env("XKCD_MAIL_FROM")?,
    36→        download: env_bool("XKCD_DOWNLOAD", true),
    37→        mail_attachment: env_bool("XKCD_MAIL_ATTACHMENT", false),
    38→        smtp_server: env("XKCD_SMTP_SERVER")?,
    39→        smtp_port: std::env::var("XKCD_SMTP_PORT")
    40→            .unwrap_or_else(|_| "587".into())
    41→            .parse()
    42→            .context("XKCD_SMTP_PORT must be a number")?,
    43→        smtp_starttls: env_bool("XKCD_SMTP_STARTTLS", true),
    44→        smtp_username: std::env::var("XKCD_SMTP_USERNAME").ok(),
    45→        smtp_password: std::env::var("XKCD_SMTP_PASSWORD").ok(),
    46→        backfill_limit: std::env::var("XKCD_BACKFILL_LIMIT")
    47→            .unwrap_or_else(|_| "5".into())
    48→            .parse()
    49→            .context("XKCD_BACKFILL_LIMIT must be a non-negative integer")?,
    50→    };
    51→
    52→    validate_config(&config)?;
    53→    Ok(config)
    54→}
    55→
    56→pub fn validate_config(config: &Config) -> anyhow::Result<()> {
    57→    if config.mail_to.is_empty() {
    58→        bail!("XKCD_MAIL_TO must contain at least one address");
    59→    }
    60→    if config.mail_attachment && !config.download {
    61→        bail!("XKCD_DOWNLOAD must be true when XKCD_MAIL_ATTACHMENT is true");
    62→    }
    63→    if config.smtp_username.is_some() != config.smtp_password.is_some() {
    64→        bail!("XKCD_SMTP_USERNAME and XKCD_SMTP_PASSWORD must both be set or both be unset");
    65→    }
    66→    Ok(())
    67→}
