     7→pub(crate) const XKCD_BASE_URL: &str = "https://xkcd.com";
     8→pub(crate) const USER_AGENT: &str = concat!("ferrous-comics/", env!("CARGO_PKG_VERSION"));
     9→
    10→#[derive(Debug, Clone, Deserialize)]
    11→pub struct Comic {
    12→    pub num: u32,
    13→    pub safe_title: String,
    14→    pub img: String,
    15→    pub alt: String,
    16→    pub year: String,
    17→    pub month: String,
    18→    pub day: String,
    19→}
    20→
    21→pub fn fetch_comic(agent: &ureq::Agent, base_url: &str) -> anyhow::Result<Comic> {
    22→    let url = format!("{}/info.0.json", base_url.trim_end_matches('/'));
    23→    let comic = agent
    24→        .get(&url)
    25→        .set("User-Agent", USER_AGENT)
    26→        .call()
    27→        .map_err(|e| match e {
    28→            ureq::Error::Status(code, _) => anyhow::anyhow!("xkcd API returned HTTP {code}"),
    29→            ureq::Error::Transport(t) => anyhow::Error::new(t).context("failed to reach xkcd API"),
    30→        })?
    31→        .into_json::<Comic>()
    32→        .context("failed to parse xkcd JSON")?;
    33→    log::debug!("fetched comic #{}: {}", comic.num, comic.safe_title);
    34→    Ok(comic)
    35→}
    36→
    37→/// Fetches a specific comic by number. Returns `Ok(None)` when xkcd returns 404
    38→/// (the comic intentionally doesn't exist, e.g. #404), and `Err` for transient failures.
    39→pub fn fetch_comic_by_num(
    40→    agent: &ureq::Agent,
    41→    base_url: &str,
    42→    num: u32,
    43→) -> anyhow::Result<Option<Comic>> {
    44→    let url = format!("{}/{}/info.0.json", base_url.trim_end_matches('/'), num);
    45→    let resp = match agent.get(&url).set("User-Agent", USER_AGENT).call() {
    46→        Ok(r) => r,
    47→        Err(ureq::Error::Status(404, _)) => return Ok(None),
    48→        Err(ureq::Error::Status(code, _)) => {
    49→            return Err(anyhow::anyhow!("xkcd API returned HTTP {code}"));
    50→        }
    51→        Err(ureq::Error::Transport(t)) => {
    52→            return Err(anyhow::Error::new(t).context("failed to reach xkcd API"));
    53→        }
    54→    };
    55→    let comic = resp
    56→        .into_json::<Comic>()
    57→        .context("failed to parse xkcd JSON")?;
    58→    anyhow::ensure!(
    59→        comic.num == num,
    60→        "xkcd API returned comic #{} for request #{}",
    61→        comic.num,
    62→        num
    63→    );
    64→    log::debug!("fetched comic #{}: {}", comic.num, comic.safe_title);
    65→    Ok(Some(comic))
    66→}
    67→
    68→pub(crate) fn local_filename(comic: &Comic) -> String {
    69→    let basename = comic.img.rsplit('/').next().unwrap_or(comic.img.as_str());
    70→    format!("{}-{}", comic.num, basename)
    71→}
    72→
    73→pub fn download_image(
    74→    agent: &ureq::Agent,
    75→    comic: &Comic,
    76→    dest_dir: &Path,
    77→) -> anyhow::Result<PathBuf> {
    78→    std::fs::create_dir_all(dest_dir).context("failed to create comics directory")?;
    79→
    80→    let filename = local_filename(comic);
    81→    let dest = dest_dir.join(&filename);
    82→
    83→    let mut bytes = Vec::new();
    84→    agent
    85→        .get(&comic.img)
    86→        .set("User-Agent", USER_AGENT)
    87→        .call()
    88→        .map_err(|e| match e {
    89→            ureq::Error::Status(code, _) => anyhow::anyhow!("image URL returned HTTP {code}"),
    90→            ureq::Error::Transport(t) => {
    91→                anyhow::Error::new(t).context("failed to fetch comic image")
    92→            }
    93→        })?
    94→        .into_reader()
    95→        .read_to_end(&mut bytes)
    96→        .context("failed to read image bytes")?;
    97→
    98→    std::fs::write(&dest, &bytes).with_context(|| format!("failed to write {}", dest.display()))?;
    99→
   100→    log::info!("downloaded {filename}");
   101→    Ok(dest)
   102→}
