    23→pub fn open_db(path: &Path) -> anyhow::Result<Database> {
    24→    Database::create(path).with_context(|| format!("failed to open database at {}", path.display()))
    25→}
    26→
    27→/// One-time migration: imports comic numbers from a legacy history file into the database,
    28→/// then renames the file to `<path>.migrated`. No-op if the file does not exist.
    29→pub fn migrate_history_file(db: &Database, path: &Path) -> anyhow::Result<()> {
    30→    if !path.exists() {
    31→        return Ok(());
    32→    }
    33→
    34→    let contents = std::fs::read_to_string(path)
    35→        .context("failed to read legacy history file for migration")?;
    36→    let nums: Vec<u32> = contents
    37→        .lines()
    38→        .filter(|l| !l.trim().is_empty())
    39→        .map(|l| l.trim().parse::<u32>())
    40→        .collect::<Result<_, _>>()
    41→        .context("invalid comic number in legacy history file")?;
    42→
    43→    let count = nums.len();
    44→    let wtx = db
    45→        .begin_write()
    46→        .context("failed to begin migration write transaction")?;
    47→    {
    48→        let mut table = wtx
    49→            .open_table(COMICS_TABLE)
    50→            .context("failed to open comics table for migration")?;
    51→        for num in nums {
    52→            if table
    53→                .get(num)
    54→                .context("failed to query comics table")?
    55→                .is_none()
    56→            {
    57→                let record = ComicRecord {
    58→                    num,
    59→                    first_seen_utc: 0, // unknown — sentinel for migrated entries
    60→                    image_downloaded: false,
    61→                    email_sent: true, // assume sent — was in history
    62→                    email_sent_utc: None,
    63→                };
    64→                let json = serde_json::to_string(&record)
    65→                    .context("failed to serialize migrated record")?;
    66→                table
    67→                    .insert(num, json.as_str())
    68→                    .context("failed to insert migrated record")?;
    69→            }
    70→        }
    71→    }
    72→    wtx.commit()
    73→        .context("failed to commit migration transaction")?;
    74→
    75→    let migrated_path = PathBuf::from(format!("{}.migrated", path.display()));
    76→    std::fs::rename(path, &migrated_path)
    77→        .context("failed to rename legacy history file after migration")?;
    78→    log::info!(
    79→        "migrated {count} comics from {} to database (backup: {})",
    80→        path.display(),
    81→        migrated_path.display()
    82→    );
    83→
    84→    Ok(())
    85→}
