    87→pub fn is_seen(db: &Database, comic: &Comic) -> anyhow::Result<bool> {
    88→    let rtx = db
    89→        .begin_read()
    90→        .context("failed to begin read transaction")?;
    91→    match rtx.open_table(COMICS_TABLE) {
    92→        Ok(table) => Ok(table
    93→            .get(comic.num)
    94→            .context("failed to query comics table")?
    95→            .is_some()),
    96→        Err(redb::TableError::TableDoesNotExist(_)) => Ok(false),
    97→        Err(e) => Err(e).context("failed to open comics table"),
    98→    }
    99→}
   100→
   101→/// Records a comic as seen immediately, before attempting download or email.
   102→/// This prevents duplicate emails if the process is re-run after a partial failure.
   103→pub fn record_first_seen(db: &Database, comic: &Comic) -> anyhow::Result<()> {
   104→    let record = ComicRecord {
   105→        num: comic.num,
   106→        first_seen_utc: std::time::SystemTime::now()
   107→            .duration_since(std::time::UNIX_EPOCH)
   108→            .unwrap_or_default()
   109→            .as_secs() as i64,
   110→        image_downloaded: false,
   111→        email_sent: false,
   112→        email_sent_utc: None,
   113→    };
   114→    let json = serde_json::to_string(&record).context("failed to serialize comic record")?;
   115→    let wtx = db
   116→        .begin_write()
   117→        .context("failed to begin write transaction")?;
   118→    {
   119→        let mut table = wtx
   120→            .open_table(COMICS_TABLE)
   121→            .context("failed to open comics table")?;
   122→        table
   123→            .insert(comic.num, json.as_str())
   124→            .context("failed to insert comic record")?;
   125→    }
   126→    wtx.commit().context("failed to commit comic record")?;
   127→    Ok(())
   128→}
   129→
   130→pub fn record_download_success(db: &Database, num: u32) -> anyhow::Result<()> {
   131→    update_record(db, num, |r| r.image_downloaded = true)
   132→}
   133→
   134→pub fn record_email_success(db: &Database, num: u32) -> anyhow::Result<()> {
   135→    update_record(db, num, |r| {
   136→        r.email_sent = true;
   137→        r.email_sent_utc = Some(
   138→            std::time::SystemTime::now()
   139→                .duration_since(std::time::UNIX_EPOCH)
   140→                .unwrap_or_default()
   141→                .as_secs() as i64,
   142→        );
   143→    })
   144→}
   145→
   146→fn update_record(db: &Database, num: u32, f: impl FnOnce(&mut ComicRecord)) -> anyhow::Result<()> {
   147→    let wtx = db
   148→        .begin_write()
   149→        .context("failed to begin write transaction")?;
   150→    {
   151→        let mut table = wtx
   152→            .open_table(COMICS_TABLE)
   153→            .context("failed to open comics table")?;
   154→        let json_str = table
   155→            .get(num)
   156→            .context("failed to query comics table")?
   157→            .with_context(|| format!("comic #{num} not found in database for update"))?
   158→            .value()
   159→            .to_owned();
   160→        let mut record: ComicRecord =
   161→            serde_json::from_str(&json_str).context("failed to deserialize comic record")?;
   162→        f(&mut record);
   163→        let json = serde_json::to_string(&record).context("failed to serialize comic record")?;
   164→        table
   165→            .insert(num, json.as_str())
   166→            .context("failed to update comic record")?;
   167→    }
   168→    wtx.commit()
   169→        .context("failed to commit comic record update")?;
   170→    Ok(())
   171→}
