    13→pub(crate) fn escape_html(s: &str) -> String {
    14→    let mut out = String::with_capacity(s.len());
    15→    for c in s.chars() {
    16→        match c {
    17→            '&' => out.push_str("&amp;"),
    18→            '<' => out.push_str("&lt;"),
    19→            '>' => out.push_str("&gt;"),
    20→            '"' => out.push_str("&quot;"),
    21→            '\'' => out.push_str("&#39;"),
    22→            _ => out.push(c),
    23→        }
    24→    }
    25→    out
    26→}
