    28→pub(crate) fn format_date(comic: &Comic) -> anyhow::Result<String> {
    29→    let year: i32 = comic.year.parse().context("invalid year")?;
    30→    let month: u32 = comic.month.parse().context("invalid month")?;
    31→    let day: u32 = comic.day.parse().context("invalid day")?;
    32→
    33→    let date = chrono::NaiveDate::from_ymd_opt(year, month, day)
    34→        .with_context(|| format!("invalid date {year}-{month}-{day}"))?;
    35→
    36→    Ok(date.format("%a %d %b %y").to_string())
    37→}
