    39→pub(crate) fn build_email(
    40→    config: &Config,
    41→    comic: &Comic,
    42→    attachment_path: Option<&Path>,
    43→) -> anyhow::Result<Message> {
    44→    let date_str = format_date(comic)?;
    45→    let subject = format!(
    46→        "New xkcd {}: {} from {}",
    47→        comic.num, comic.safe_title, date_str
    48→    );
    49→    let comic_url = format!("https://xkcd.com/{}/", comic.num);
    50→    let plain_text = format!("{}\n{}\n\n{}", comic.safe_title, comic_url, comic.alt);
    51→    let html_body = format!(
    52→        r#"<!DOCTYPE html>
    53→<html>
    54→<head>
    55→<meta charset="utf-8">
    56→<style>
    57→  body{{font-family:sans-serif;max-width:640px;margin:0 auto;padding:16px;background:#fff;color:#222}}
    58→  h1{{font-size:1.1em;margin:0 0 4px 0}}
    59→  .meta{{color:#666;font-size:0.85em;margin-bottom:14px}}
    60→  .comic img{{max-width:100%;height:auto;display:block}}
    61→  .alt{{background:#f5f5f5;border-left:3px solid #999;padding:8px 12px;margin:12px 0;font-style:italic;font-size:0.95em}}
    62→  .footer{{font-size:0.8em;color:#aaa;margin-top:20px;border-top:1px solid #eee;padding-top:8px}}
    63→  a{{color:#1a0dab}}
    64→</style>
    65→</head>
    66→<body>
    67→<h1><a href="{url}">{title}</a></h1>
    68→<div class="meta">#{num} &middot; {date}</div>
    69→<div class="comic"><a href="{url}"><img src="{img}" alt="{alt}" title="{title}" style="max-width:100%;display:block"></a></div>
    70→<div class="alt">{alt}</div>
    71→<div class="footer">Mailed by <a href="https://github.com/bryanhiestand/ferrous-comics">ferrous-comics</a></div>
    72→</body>
    73→</html>"#,
    74→        url = escape_html(&comic_url),
    75→        img = escape_html(&comic.img),
    76→        title = escape_html(&comic.safe_title),
    77→        alt = escape_html(&comic.alt),
    78→        num = comic.num,
    79→        date = escape_html(&date_str),
    80→    );
    81→
    82→    let alternative = MultiPart::alternative()
    83→        .singlepart(SinglePart::plain(plain_text))
    84→        .singlepart(SinglePart::html(html_body));
    85→
    86→    let body = if let Some(path) = attachment_path {
    87→        let filename = local_filename(comic);
    88→        let image_bytes = std::fs::read(path)
    89→            .with_context(|| format!("failed to read attachment {}", path.display()))?;
    90→        let content_type = match path.extension().and_then(|e| e.to_str()) {
    91→            Some("png") => ContentType::parse("image/png").unwrap(),
    92→            Some("jpg") | Some("jpeg") => ContentType::parse("image/jpeg").unwrap(),
    93→            Some("gif") => ContentType::parse("image/gif").unwrap(),
    94→            _ => ContentType::parse("application/octet-stream").unwrap(),
    95→        };
    96→        MultiPart::mixed()
    97→            .multipart(alternative)
    98→            .singlepart(Attachment::new(filename).body(image_bytes, content_type))
    99→    } else {
   100→        alternative
   101→    };
   102→
   103→    let mut builder = Message::builder().from(
   104→        config
   105→            .mail_from
   106→            .parse()
   107→            .context("invalid XKCD_MAIL_FROM address")?,
   108→    );
   109→    for addr in &config.mail_to {
   110→        builder = builder.to(addr
   111→            .parse()
   112→            .with_context(|| format!("invalid XKCD_MAIL_TO address: {addr}"))?);
   113→    }
   114→    builder
   115→        .subject(&subject)
   116→        .multipart(body)
   117→        .context("failed to build email message")
   118→}
   119→
   120→fn build_transport(config: &Config) -> anyhow::Result<SmtpTransport> {
   121→    let builder = if config.smtp_starttls {
   122→        SmtpTransport::starttls_relay(&config.smtp_server)
   123→            .context("failed to create STARTTLS transport")?
   124→    } else {
   125→        SmtpTransport::relay(&config.smtp_server)
   126→            .context("failed to create SMTP relay transport")?
   127→    };
   128→
   129→    let builder = builder.port(config.smtp_port);
   130→
   131→    let builder = match (&config.smtp_username, &config.smtp_password) {
   132→        (Some(user), Some(pass)) => {
   133→            builder.credentials(Credentials::new(user.clone(), pass.clone()))
   134→        }
   135→        _ => builder,
   136→    };
   137→
   138→    Ok(builder.build())
   139→}
