   141→pub fn send_email(
   142→    config: &Config,
   143→    comic: &Comic,
   144→    attachment_path: Option<&Path>,
   145→) -> anyhow::Result<()> {
   146→    let email = build_email(config, comic, attachment_path)?;
   147→    let transport = build_transport(config)?;
   148→    transport.send(&email).context("SMTP send failed")?;
   149→    log::info!("emailed comic #{}: {}", comic.num, comic.safe_title);
   150→    Ok(())
   151→}
