   158→    /// Helper: compute backfill candidates using the same logic as main()
   159→    fn backfill_candidates(last: Option<u32>, latest: u32, limit: u32) -> Vec<u32> {
   160→        let start = last.map(|n| n.saturating_add(1)).unwrap_or_else(|| {
   161→            if limit > 0 {
   162→                latest.saturating_sub(limit - 1)
   163→            } else {
   164→                latest
   165→            }
   166→        });
   167→        if limit > 0 {
   168→            (start..=latest).take(limit as usize).collect()
   169→        } else {
   170→            vec![latest]
   171→        }
   172→    }
   173→
