     1→use std::io::Write;
     2→use std::path::{Path, PathBuf};
     3→
     4→use anyhow::Context;
     5→use redb::{Database, ReadableTable, TableDefinition};
     6→use serde::{Deserialize, Serialize};
     7→
     8→use crate::http::Comic;
     9→
    10→pub(crate) const COMICS_TABLE: TableDefinition<u32, &str> = TableDefinition::new("comics");
    11→
    12→#[derive(Debug, Serialize, Deserialize)]
    13→pub struct ComicRecord {
    14→    pub num: u32,
    15→    /// Unix timestamp (seconds). 0 means migrated from legacy file — timestamp unknown.
    16→    pub first_seen_utc: i64,
    17→    pub image_downloaded: bool,
    18→    pub email_sent: bool,
    19→    /// Unix timestamp of successful email send, if any.
    20→    pub email_sent_utc: Option<i64>,
    21→}
    22→
    23→pub fn open_db(path: &Path) -> anyhow::Result<Database> {
    24→    Database::create(path).with_context(|| format!("failed to open database at {}", path.display()))
    25→}
    26→
    27→/// One-time migration: imports comic numbers from a legacy history file into the database,
    28→/// then renames the file to `<path>.migrated`. No-op if the file does not exist.
    29→pub fn migrate_history_file(db: &Database, path: &Path) -> anyhow::Result<()> {
    30→    if !path.exists() {
    31→        return Ok(());
    32→    }
    33→
    34→    let contents = std::fs::read_to_string(path)
    35→        .context("failed to read legacy history file for migration")?;
    36→    let nums: Vec<u32> = contents
    37→        .lines()
    38→        .filter(|l| !l.trim().is_empty())
    39→        .map(|l| l.trim().parse::<u32>())
    40→        .collect::<Result<_, _>>()
    41→        .context("invalid comic number in legacy history file")?;
    42→
    43→    let count = nums.len();
    44→    let wtx = db
    45→        .begin_write()
    46→        .context("failed to begin migration write transaction")?;
    47→    {
    48→        let mut table = wtx
    49→            .open_table(COMICS_TABLE)
    50→            .context("failed to open comics table for migration")?;
    51→        for num in nums {
    52→            if table
    53→                .get(num)
    54→                .context("failed to query comics table")?
    55→                .is_none()
    56→            {
    57→                let record = ComicRecord {
    58→                    num,
    59→                    first_seen_utc: 0, // unknown — sentinel for migrated entries
    60→                    image_downloaded: false,
    61→                    email_sent: true, // assume sent — was in history
    62→                    email_sent_utc: None,
    63→                };
    64→                let json = serde_json::to_string(&record)
    65→                    .context("failed to serialize migrated record")?;
    66→                table
    67→                    .insert(num, json.as_str())
    68→                    .context("failed to insert migrated record")?;
    69→            }
    70→        }
    71→    }
    72→    wtx.commit()
    73→        .context("failed to commit migration transaction")?;
    74→
    75→    let migrated_path = PathBuf::from(format!("{}.migrated", path.display()));
    76→    std::fs::rename(path, &migrated_path)
    77→        .context("failed to rename legacy history file after migration")?;
    78→    log::info!(
    79→        "migrated {count} comics from {} to database (backup: {})",
    80→        path.display(),
    81→        migrated_path.display()
    82→    );
    83→
    84→    Ok(())
    85→}
    86→
    87→pub fn is_seen(db: &Database, comic: &Comic) -> anyhow::Result<bool> {
    88→    let rtx = db
    89→        .begin_read()
    90→        .context("failed to begin read transaction")?;
    91→    match rtx.open_table(COMICS_TABLE) {
    92→        Ok(table) => Ok(table
    93→            .get(comic.num)
    94→            .context("failed to query comics table")?
    95→            .is_some()),
    96→        Err(redb::TableError::TableDoesNotExist(_)) => Ok(false),
    97→        Err(e) => Err(e).context("failed to open comics table"),
    98→    }
    99→}
   100→
   101→/// Records a comic as seen immediately, before attempting download or email.
   102→/// This prevents duplicate emails if the process is re-run after a partial failure.
   103→pub fn record_first_seen(db: &Database, comic: &Comic) -> anyhow::Result<()> {
   104→    let record = ComicRecord {
   105→        num: comic.num,
   106→        first_seen_utc: std::time::SystemTime::now()
   107→            .duration_since(std::time::UNIX_EPOCH)
   108→            .unwrap_or_default()
   109→            .as_secs() as i64,
   110→        image_downloaded: false,
   111→        email_sent: false,
   112→        email_sent_utc: None,
   113→    };
   114→    let json = serde_json::to_string(&record).context("failed to serialize comic record")?;
   115→    let wtx = db
   116→        .begin_write()
   117→        .context("failed to begin write transaction")?;
   118→    {
   119→        let mut table = wtx
   120→            .open_table(COMICS_TABLE)
   121→            .context("failed to open comics table")?;
   122→        table
   123→            .insert(comic.num, json.as_str())
   124→            .context("failed to insert comic record")?;
   125→    }
   126→    wtx.commit().context("failed to commit comic record")?;
   127→    Ok(())
   128→}
