   134→pub fn record_email_success(db: &Database, num: u32) -> anyhow::Result<()> {
   135→    update_record(db, num, |r| {
   136→        r.email_sent = true;
   137→        r.email_sent_utc = Some(
   138→            std::time::SystemTime::now()
   139→                .duration_since(std::time::UNIX_EPOCH)
   140→                .unwrap_or_default()
   141→                .as_secs() as i64,
   142→        );
   143→    })
   144→}
   145→
   146→fn update_record(db: &Database, num: u32, f: impl FnOnce(&mut ComicRecord)) -> anyhow::Result<()> {
   147→    let wtx = db
   148→        .begin_write()
   149→        .context("failed to begin write transaction")?;
   150→    {
   151→        let mut table = wtx
   152→            .open_table(COMICS_TABLE)
   153→            .context("failed to open comics table")?;
   154→        let json_str = table
   155→            .get(num)
   156→            .context("failed to query comics table")?
   157→            .with_context(|| format!("comic #{num} not found in database for update"))?
   158→            .value()
   159→            .to_owned();
   160→        let mut record: ComicRecord =
   161→            serde_json::from_str(&json_str).context("failed to deserialize comic record")?;
   162→        f(&mut record);
   163→        let json = serde_json::to_string(&record).context("failed to serialize comic record")?;
   164→        table
   165→            .insert(num, json.as_str())
   166→            .context("failed to update comic record")?;
   167→    }
   168→    wtx.commit()
   169→        .context("failed to commit comic record update")?;
   170→    Ok(())
   171→}
