   173→/// Returns the highest comic number recorded in the database, or `None` if empty.
   174→pub fn last_seen_num(db: &Database) -> anyhow::Result<Option<u32>> {
   175→    let rtx = db
   176→        .begin_read()
   177→        .context("failed to begin read transaction")?;
   178→    match rtx.open_table(COMICS_TABLE) {
   179→        Ok(table) => Ok(table
   180→            .last()
   181→            .context("failed to read last entry from comics table")?
   182→            .map(|(k, _)| k.value())),
   183→        Err(redb::TableError::TableDoesNotExist(_)) => Ok(None),
   184→        Err(e) => Err(e).context("failed to open comics table"),
   185→    }
   186→}
   187→
   188→/// Prints all comic records in the database as newline-delimited JSON, sorted by comic number.
   189→pub fn cmd_dump(db: &Database, out: &mut impl Write) -> anyhow::Result<()> {
   190→    let rtx = db
   191→        .begin_read()
   192→        .context("failed to begin read transaction")?;
   193→    match rtx.open_table(COMICS_TABLE) {
   194→        Ok(table) => {
   195→            for entry in table.iter().context("failed to iterate comics table")? {
   196→                let (_, value) = entry.context("failed to read comics table entry")?;
   197→                writeln!(out, "{}", value.value()).context("failed to write output")?;
   198→            }
   199→            Ok(())
   200→        }
   201→        Err(redb::TableError::TableDoesNotExist(_)) => Ok(()), // empty database
   202→        Err(e) => Err(e).context("failed to open comics table"),
   203→    }
   204→}
