    10→#[derive(Debug, Clone, Deserialize)]
    11→pub struct Comic {
    12→    pub num: u32,
    13→    pub safe_title: String,
    14→    pub img: String,
    15→    pub alt: String,
    16→    pub year: String,
    17→    pub month: String,
    18→    pub day: String,
