    37→/// Fetches a specific comic by number. Returns `Ok(None)` when xkcd returns 404
    38→/// (the comic intentionally doesn't exist, e.g. #404), and `Err` for transient failures.
    39→pub fn fetch_comic_by_num(
    40→    agent: &ureq::Agent,
    41→    base_url: &str,
    42→    num: u32,
    43→) -> anyhow::Result<Option<Comic>> {
    44→    let url = format!("{}/{}/info.0.json", base_url.trim_end_matches('/'), num);
    45→    let resp = match agent.get(&url).set("User-Agent", USER_AGENT).call() {
    46→        Ok(r) => r,
    47→        Err(ureq::Error::Status(404, _)) => return Ok(None),
    48→        Err(ureq::Error::Status(code, _)) => {
    49→            return Err(anyhow::anyhow!("xkcd API returned HTTP {code}"));
    50→        }
    51→        Err(ureq::Error::Transport(t)) => {
    52→            return Err(anyhow::Error::new(t).context("failed to reach xkcd API"));
    53→        }
    54→    };
    55→    let comic = resp
    56→        .into_json::<Comic>()
    57→        .context("failed to parse xkcd JSON")?;
    58→    anyhow::ensure!(
    59→        comic.num == num,
    60→        "xkcd API returned comic #{} for request #{}",
    61→        comic.num,
    62→        num
    63→    );
    64→    log::debug!("fetched comic #{}: {}", comic.num, comic.safe_title);
    65→    Ok(Some(comic))
    66→}
