    93→            Some("gif") => ContentType::parse("image/gif").unwrap(),
    94→            _ => ContentType::parse("application/octet-stream").unwrap(),
    95→        };
    96→        MultiPart::mixed()
    97→            .multipart(alternative)
    98→            .singlepart(Attachment::new(filename).body(image_bytes, content_type))
    99→    } else {
   100→        alternative
