   120→fn build_transport(config: &Config) -> anyhow::Result<SmtpTransport> {
   121→    let builder = if config.smtp_starttls {
   122→        SmtpTransport::starttls_relay(&config.smtp_server)
   123→            .context("failed to create STARTTLS transport")?
   124→    } else {
   125→        SmtpTransport::relay(&config.smtp_server)
   126→            .context("failed to create SMTP relay transport")?
   127→    };
   128→
   129→    let builder = builder.port(config.smtp_port);
   130→
   131→    let builder = match (&config.smtp_username, &config.smtp_password) {
   132→        (Some(user), Some(pass)) => {
   133→            builder.credentials(Credentials::new(user.clone(), pass.clone()))
   134→        }
   135→        _ => builder,
   136→    };
   137→
   138→    Ok(builder.build())
   139→}
